        val transaction = PaymentSecurityModule.PaymentTransaction(
            transactionId = generateTransactionId(),
            amount = amount,
            currency = currency,
            timestamp = System.currentTimeMillis(),
            walletId = walletId
        )

        return securityModule.processPayment(transaction)
    }

    suspend fun processInAppPurchase(
        productId: String,
        amount: Double,
        currency: String,
        cardData: String? = null
    ): PaymentSecurityModule.PaymentResult {
        val transaction = PaymentSecurityModule.PaymentTransaction(
            transactionId = generateTransactionId(),
            amount = amount,
            currency = currency,
            timestamp = System.currentTimeMillis()
        )

        return securityModule.processPayment(transaction, cardData)
    }

    private fun generateTransactionId(): String {
        return "TXN_${System.currentTimeMillis()}_${java.util.UUID.randomUUID()}"
    }
